import{_ as e,C as l,o as t,c as i,a2 as s,E as r}from"./chunks/framework.BnBoz4Zl.js";const p="/anjian-workbuddy-bluebook-site/assets/001_image_TBeUbtO5Uo.D64OTo-i.png",o="/anjian-workbuddy-bluebook-site/assets/002_image_UsfnbdO18o.CSB_ppVo.png",d="/anjian-workbuddy-bluebook-site/assets/003_image_D9dBbor45o.BJ3jEORy.png",h="/anjian-workbuddy-bluebook-site/assets/004_image_SgdBbN3bXo.BP2PdE0O.png",c="/anjian-workbuddy-bluebook-site/assets/005_image_IrhFbSsgxo.gLeZo_Ec.png",b="/anjian-workbuddy-bluebook-site/assets/006_image_OmoDbu7rBo.Cp59HOpn.png",g="/anjian-workbuddy-bluebook-site/assets/007_image_YCTubyoc3o.CSMTBWOw.png",k="/anjian-workbuddy-bluebook-site/assets/008_image_Cezibb1uao.BRT3flS0.png",u="/anjian-workbuddy-bluebook-site/assets/009_image_YB8xbAm4Zo.B4NXc3IO.png",_="/anjian-workbuddy-bluebook-site/assets/010_image_FUCAbuw08o.Ax8iL3ns.png",m="/anjian-workbuddy-bluebook-site/assets/011_image_VrCsbV8TPo.DKsygJqr.png",E="/anjian-workbuddy-bluebook-site/assets/012_image_WzaxbhMT7o.SR7BiUC9.png",f="/anjian-workbuddy-bluebook-site/assets/013_image_KqQsbAw8Ho.DE1YyFhG.png",B="/anjian-workbuddy-bluebook-site/assets/014_image_GUBtbiSfao.DZxt3VE1.png",A="/anjian-workbuddy-bluebook-site/assets/015_image_QHmHbuB4Ro.BCCHQNFd.png",x="/anjian-workbuddy-bluebook-site/assets/016_image_NtnjbhJRHo.BOqNsQe4.png",S=JSON.parse('{"title":"第 20 章 自媒体不只是靠努力，而是一条增长闭环","description":"一个人做自媒体，做自媒体最浪费时间的事，就是一上来就把内容打磨到满分。 听起来很反常识，但我真踩过这个坑。你写得很深，资料查得很全，结构改了三遍。结果发出去，阅读量个位数。 后来我才意识到，起号前期真正要先解决的，不是“写得够不够好”，而是“有没有人愿意点进来”。","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 20 章 自媒体不只是靠努力，而是一条增长闭环/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 20 章 自媒体不只是靠努力，而是一条增长闭环/index.md","lastUpdated":1783659790000}'),y={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 20 章 自媒体不只是靠努力，而是一条增长闭环/index.md"};function v(q,a,C,P,D,w){const n=l("MermaidDiagram");return t(),i("div",null,[a[0]||(a[0]=s('<h1 id="第-20-章-自媒体不只是靠努力-而是一条增长闭环" tabindex="-1">第 20 章 自媒体不只是靠努力，而是一条增长闭环 <a class="header-anchor" href="#第-20-章-自媒体不只是靠努力-而是一条增长闭环" aria-label="Permalink to &quot;第 20 章 自媒体不只是靠努力，而是一条增长闭环&quot;">​</a></h1><h2 id="内容没人看-往往不是因为你不够努力" tabindex="-1">内容没人看？往往不是因为你不够努力 <a class="header-anchor" href="#内容没人看-往往不是因为你不够努力" aria-label="Permalink to &quot;内容没人看？往往不是因为你不够努力&quot;">​</a></h2><p>一个人做自媒体，做自媒体最浪费时间的事，就是一上来就把内容打磨到满分。</p><p>听起来很反常识，但我真踩过这个坑。你写得很深，资料查得很全，结构改了三遍。结果发出去，阅读量个位数。</p><p>后来我才意识到，起号前期真正要先解决的，不是“写得够不够好”，而是“有没有人愿意点进来”。</p><h2 id="工作流" tabindex="-1">工作流 <a class="header-anchor" href="#工作流" aria-label="Permalink to &quot;工作流&quot;">​</a></h2>',6)),r(n,{graph:"flowchart%20LR%0A%20%20%20%20A%5B%E8%B6%8B%E5%8A%BF%E3%80%81%E8%AF%84%E8%AE%BA%E4%B8%8E%E7%94%A8%E6%88%B7%E9%97%AE%E9%A2%98%5D%20--%3E%20B%5B%E9%80%89%E9%A2%98%E6%B1%A0%5D%0A%20%20%20%20B%20--%3E%20C%5B%E4%BA%8B%E5%AE%9E%E5%8C%85%E4%B8%8E%E8%A7%82%E7%82%B9%5D%0A%20%20%20%20C%20--%3E%20D%5B%E6%A0%87%E9%A2%98%E5%92%8C%E7%BB%93%E6%9E%84%5D%0A%20%20%20%20D%20--%3E%20E%5B%E5%85%AC%E4%BC%97%E5%8F%B7%20%2F%20%E5%B0%8F%E7%BA%A2%E4%B9%A6%20%2F%20%E8%A7%86%E9%A2%91%E8%84%9A%E6%9C%AC%5D%0A%20%20%20%20E%20--%3E%20F%5B%E5%B0%81%E9%9D%A2%E3%80%81%E9%95%BF%E5%9B%BE%E4%B8%8E%E5%88%86%E9%95%9C%5D%0A%20%20%20%20F%20--%3E%20G%5B%E5%90%88%E8%A7%84%E5%92%8C%E5%8F%91%E5%B8%83%E5%89%8D%E4%BD%93%E6%A3%80%5D%0A%20%20%20%20G%20--%3E%20H%5B%E8%8D%89%E7%A8%BF%E6%88%96%E4%BA%BA%E5%B7%A5%E5%8F%91%E5%B8%83%5D%0A%20%20%20%20H%20--%3E%20I%5B%E6%95%B0%E6%8D%AE%E4%B8%8E%E4%BA%BA%E5%B7%A5%E4%BF%AE%E6%94%B9%E5%9B%9E%E6%B5%81%5D%0A%20%20%20%20I%20--%3E%20B%0A"}),a[1]||(a[1]=s(`<p>Skill 的作用是补上其中一个环节，不是接管账号判断。下面用八个具体工作现场说明。</p><h2 id="场景一-每天刷热点-仍然不知道账号该写什么" tabindex="-1">场景一：每天刷热点，仍然不知道账号该写什么 <a class="header-anchor" href="#场景一-每天刷热点-仍然不知道账号该写什么" aria-label="Permalink to &quot;场景一：每天刷热点，仍然不知道账号该写什么&quot;">​</a></h2><p>热榜告诉你“大家正在看什么”，却不告诉你“这个账号为什么值得写”。只跟热点，容易得到同质化内容；只凭感觉，又很难判断用户是否真的关心。</p><ul><li><a href="https://skillhub.cn/skills/gzh-explosive-content-detector" target="_blank" rel="noreferrer">公众号热门文章查询</a>：观察同主题热门文章；</li><li><a href="https://skillhub.cn/skills/xhs-hotnotes" target="_blank" rel="noreferrer">小红书爆款笔记查询</a>：获取热门笔记和数据线索；</li><li><a href="https://skillhub.cn/skills/xhs-comment-insights" target="_blank" rel="noreferrer">小红书评论洞察</a>：从评论中提取问题、反对意见和未满足需求；</li><li><a href="https://skillhub.cn/skills/inspiration-hunter-skill" target="_blank" rel="noreferrer">灵感捕手</a>：把临时想到的角度放进统一收件箱。</li></ul><h3 id="指令怎样写" tabindex="-1">指令怎样写 <a class="header-anchor" href="#指令怎样写" aria-label="Permalink to &quot;指令怎样写&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>围绕“AI 办公自动化”建立本周选题池，不直接写文章。</span></span>
<span class="line"><span>分别收集公众号与小红书近 30 天的高互动内容，记录标题、发布日期、</span></span>
<span class="line"><span>核心承诺、内容结构、互动信号和原链接。</span></span>
<span class="line"><span>再从评论中提取：重复问题、反对意见、失败经历和用户原话。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>结合我的账号定位：面向非技术职场人，强调真实流程和结果验收。</span></span>
<span class="line"><span>输出 12 个候选选题，每个包含：目标读者、真实问题、已有内容缺口、</span></span>
<span class="line"><span>我能提供的新证据、适合平台、制作成本和时效性。</span></span>
<span class="line"><span>不要把阅读量高直接解释成选题一定适合我。</span></span></code></pre></div><p><img src="`+p+'" alt="" loading="lazy"></p><h3 id="执行流程与结果" tabindex="-1">执行流程与结果 <a class="header-anchor" href="#执行流程与结果" aria-label="Permalink to &quot;执行流程与结果&quot;">​</a></h3><p>WorkBuddy 先生成跨平台样本表，再把评论聚成问题簇，最后把“热度、账号匹配、新增价值、证据充足度、制作成本”分别评分。交付物是一张可以人工删选的选题看板。</p><p><img src="'+o+'" alt="" loading="lazy"></p><h3 id="有时候光找热门还不够-我们还需要去找低粉爆款。" tabindex="-1"><strong>有时候光找热门还不够，我们还需要去找低粉爆款。</strong> <a class="header-anchor" href="#有时候光找热门还不够-我们还需要去找低粉爆款。" aria-label="Permalink to &quot;**有时候光找热门还不够，我们还需要去找低粉爆款。**&quot;">​</a></h3><p>大家应该都听过，<strong>起号要找低粉爆款去抄</strong>，这确实是这样的。</p><p><em>PS：这里说的抄，是抄选题，不是原封不动的抄内容。</em></p><p>推荐一个叫<a href="https://github.com/kangarooking/kangarooking-skills/tree/main/viral-topic" target="_blank" rel="noreferrer"><strong>viral-topic</strong></a><strong>的skill</strong>，它可以获取各个平台近期的指定领域的多个低粉爆款内容。</p><p>比如获取公众号最近7天的AI领域低粉爆款文章。</p><p><img src="'+d+'" alt="" loading="lazy"></p><p>筛选X上的低粉爆款</p><p><img src="'+h+'" alt="" loading="lazy"></p><p>以及YouTube的低粉爆款</p><p><img src="'+c+`" alt="" loading="lazy"></p><h2 id="场景二-想要爆款标题-但不想标题党" tabindex="-1">场景二：想要爆款标题，但不想标题党 <a class="header-anchor" href="#场景二-想要爆款标题-但不想标题党" aria-label="Permalink to &quot;场景二：想要爆款标题，但不想标题党&quot;">​</a></h2><p>“给我 20 个爆款标题”很容易得到数字、悬念和夸张承诺，却没有任何标题能准确兑现正文。标题不是独立文案，它是读者与正文之间的一份承诺。</p><ul><li><a href="https://skillhub.cn/skills/gzh-official-account-title-generator" target="_blank" rel="noreferrer">公众号标题生成与评分</a>；</li><li><a href="https://skillhub.cn/skills/redbook-writer" target="_blank" rel="noreferrer">小红书爆款笔记自动生成器</a>中的标题与标签模块；</li><li><a href="https://skillhub.cn/skills/bozo-video-gz" target="_blank" rel="noreferrer">短视频钩子方案生成</a>。</li></ul><h3 id="指令怎样写-1" tabindex="-1">指令怎样写 <a class="header-anchor" href="#指令怎样写-1" aria-label="Permalink to &quot;指令怎样写&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>读取 approved-article.md，只根据正文已经出现的事实生成标题。</span></span>
<span class="line"><span>分别生成：公众号标题 8 个、小红书标题 8 个、短视频开场钩子 5 个。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每个候选都输出：</span></span>
<span class="line"><span>1. 面向谁；2. 承诺什么；3. 正文哪一段能够兑现；</span></span>
<span class="line"><span>4. 采用的问题/结果/清单/案例/反常识角度；</span></span>
<span class="line"><span>5. 可信度、具体性、平台适配和夸大风险评分。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>删除无法证明的数字、绝对化承诺、虚假稀缺和与正文不一致的结论。</span></span>
<span class="line"><span>不要自动选择最终标题，先让我确认内容承诺。</span></span></code></pre></div><p><img src="`+b+'" alt="" loading="lazy"></p><h3 id="验收方法" tabindex="-1">验收方法 <a class="header-anchor" href="#验收方法" aria-label="Permalink to &quot;验收方法&quot;">​</a></h3><p>把标题单独给一个不了解正文的人看，请他写出“我预计点进去会得到什么”。再与正文核对。预期与实际不一致，标题分数再高也不能用。</p><p>workbuddy通过这几个skill，生成的标题还真有那味儿。特别是小红书的标题，很有小红书的感觉。</p><p><img src="'+g+'" alt="" loading="lazy"></p><p>可以进行 A/B 测试，但一次只改变一个主要变量，例如“问题式”与“结果式”。不要同时改标题、封面、发布时间和正文开头，否则数据无法解释。</p><p>再推荐一个标题skill：<a href="https://github.com/kangarooking/kangarooking-skills/tree/main/viral-title" target="_blank" rel="noreferrer"><strong>viral-</strong></a><a href="https://github.com/kangarooking/kangarooking-skills/tree/main/viral-title" target="_blank" rel="noreferrer"><strong>title</strong></a><strong>，很适合用来给公众号起标题</strong></p><p><img src="'+k+`" alt="" loading="lazy"></p><h2 id="场景三-公众号封面每次从空白画布开始" tabindex="-1">场景三：公众号封面每次从空白画布开始 <a class="header-anchor" href="#场景三-公众号封面每次从空白画布开始" aria-label="Permalink to &quot;场景三：公众号封面每次从空白画布开始&quot;">​</a></h2><p>封面既要让人看懂主题，又要适配大小封面、安全区和账号品牌。直接说“做一张高级感封面”，通常会得到与正文无关的装饰图、错误文字或失真的 Logo。</p><ul><li><a href="https://skillhub.cn/skills/explosive-cover-generator-gzh" target="_blank" rel="noreferrer">公众号爆款封面生成</a>：分析同赛道视觉规律并给出方案；</li><li><a href="https://skillhub.cn/skills/generate-wechat-official-account-images" target="_blank" rel="noreferrer">公众号图片生成器</a>：处理大小封面、文内配图和引导图；</li><li>海报设计或图像生成 Skill：执行已确认的视觉 brief。</li></ul><h3 id="指令怎样写-2" tabindex="-1">指令怎样写 <a class="header-anchor" href="#指令怎样写-2" aria-label="Permalink to &quot;指令怎样写&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>为文章《收藏不是知识管理，能再次用起来才是》制作公众号封面 brief。</span></span>
<span class="line"><span>目标读者：知识工作者；核心信息：从收藏走向可复用知识流。</span></span>
<span class="line"><span>品牌色：#1677FF、白、黑；禁止紫色渐变、夸张科技光效和虚构产品界面。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>先输出 3 个构图方向，每个包含：主体、层级、封面文案、色彩、留白、</span></span>
<span class="line"><span>大小封面裁切风险和正文对应段落。我确认后再生成图片。</span></span>
<span class="line"><span>生成后检查：文字是否准确、Logo 是否变形、主体是否被小封面裁掉、</span></span>
<span class="line"><span>是否使用未经授权的人物或素材。不要直接上传公众号。</span></span></code></pre></div><h3 id="结果是否可用" tabindex="-1">结果是否可用 <a class="header-anchor" href="#结果是否可用" aria-label="Permalink to &quot;结果是否可用&quot;">​</a></h3><p><img src="`+u+`" alt="" loading="lazy"></p><p>生成的封面还不错，有汉字、封面负责表达的主题也比较贴切，如果换成更强的生图模型，效果应该会更好。</p><h2 id="场景四-小红书不只是-把长文切成九张图" tabindex="-1">场景四：小红书不只是“把长文切成九张图” <a class="header-anchor" href="#场景四-小红书不只是-把长文切成九张图" aria-label="Permalink to &quot;场景四：小红书不只是“把长文切成九张图”&quot;">​</a></h2><p>公众号文章改成小红书时，常见做法是截短段落、加入表情符号，再把文字铺到九张卡片上。结果信息很多，但封面没有钩子，第二页没有承接，最后一页没有行动，移动端也难读。</p><ul><li><a href="https://skillhub.cn/skills/xiaohongshu-cover" target="_blank" rel="noreferrer">小红书封面图制作</a>；</li><li><a href="https://skillhub.cn/skills/any2xiaohongshu" target="_blank" rel="noreferrer">小红书图片生成器</a>：将结构化内容渲染为竖版卡片；</li><li><a href="https://skillhub.cn/skills/xhs-ops-copilot" target="_blank" rel="noreferrer">小红书运营副驾</a>：发布前体检与复盘。</li></ul><h3 id="工作流-1" tabindex="-1">工作流 <a class="header-anchor" href="#工作流-1" aria-label="Permalink to &quot;工作流&quot;">​</a></h3><ol><li>从长文提取不带平台语气的事实包；</li><li>选择一个核心问题，删除与它无关的支线；</li><li>设计“封面承诺 → 问题共鸣 → 方法 → 示例 → 误区 → 清单”的滑动节奏；</li><li>先输出逐页线框和字数，再生成图片；</li><li>在真实手机宽度检查字号、断行、边距和重点；</li><li>最终标题、正文、标签和图片逐一核对数字与专有名词。</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>把 approved-article.md 改造成 8 页小红书图文，不新增事实。</span></span>
<span class="line"><span>第 1 页只表达一个承诺；第 2 页写读者正在经历的问题；</span></span>
<span class="line"><span>第 3-6 页每页只讲一个动作并给一个例子；第 7 页写常见误区；</span></span>
<span class="line"><span>第 8 页给可保存的检查清单。</span></span>
<span class="line"><span>先返回逐页文案、视觉层级和预计字数，我确认后再调用封面与长图 Skill。</span></span></code></pre></div><p><img src="`+_+`" alt="" loading="lazy"></p><h2 id="场景五-一段长文怎样变成可拍的短视频" tabindex="-1">场景五：一段长文怎样变成可拍的短视频 <a class="header-anchor" href="#场景五-一段长文怎样变成可拍的短视频" aria-label="Permalink to &quot;场景五：一段长文怎样变成可拍的短视频&quot;">​</a></h2><p>“改成 60 秒口播”通常只是把文章压缩成更快的朗读稿，没有镜头、节奏、证据画面和停顿，也没有说明谁能拍、需要什么素材。</p><ul><li><a href="https://skillhub.cn/skills/short-video-topic-research" target="_blank" rel="noreferrer">短视频选题素材研究</a>；</li><li><a href="https://skillhub.cn/skills/shortvideo-content-factory-cn-v1-zt" target="_blank" rel="noreferrer">短视频脚本与矩阵内容工厂</a>；</li><li><a href="https://skillhub.cn/skills/seedance-director" target="_blank" rel="noreferrer">AI 短视频导演</a>用于分镜和生成提示；</li><li>配乐 Skill 只在确认版权和商用范围后使用。</li></ul><h3 id="指令怎样写-3" tabindex="-1">指令怎样写 <a class="header-anchor" href="#指令怎样写-3" aria-label="Permalink to &quot;指令怎样写&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>把这篇文章改造成 60 秒真人口播，目标是让第一次使用 WorkBuddy 的人</span></span>
<span class="line"><span>理解“为什么任务简报比一句模糊需求更重要”。</span></span>
<span class="line"><span>输出时间轴表格：时长、景别、画面、口播、屏幕文字、素材来源、转场。</span></span>
<span class="line"><span>前 3 秒必须提出真实问题，不夸大收益；20 秒前展示一次产品过程证据；</span></span>
<span class="line"><span>结尾给一个可以立即尝试的指令，不做虚假互动承诺。</span></span>
<span class="line"><span>同时列出必须实拍、可用产品截图、可由 AI 生成的画面，禁止伪造用户反馈。</span></span></code></pre></div><p><img src="`+m+'" alt="" loading="lazy"></p><p>生成的口播文案，效果还不错哦。</p><h2 id="场景六-发布前-别让自动化越过责任边界" tabindex="-1">场景六：发布前，别让自动化越过责任边界 <a class="header-anchor" href="#场景六-发布前-别让自动化越过责任边界" aria-label="Permalink to &quot;场景六：发布前，别让自动化越过责任边界&quot;">​</a></h2><ul><li><a href="https://skillhub.cn/skills/gzh-prohibited-word" target="_blank" rel="noreferrer">公众号违禁词检测</a>：标记风险表达；</li><li><a href="https://skillhub.cn/skills/md-to-wechat" target="_blank" rel="noreferrer">公众号排版 Skill</a>：渲染 Markdown 并创建草稿；</li><li><a href="https://skillhub.cn/skills/unclecheng-reduce-ai-perception-v2" target="_blank" rel="noreferrer">文章去 AI 味工具</a>：只用于减少套话，不用于伪装来源或原创。</li></ul><div class="language-Plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>检查本次公众号文章是否有违禁词，如有请标记出来，并对每个违禁词给出修改建议。检查整体内容的 AI 味，并降低AI味，最后把文章排版。</span></span></code></pre></div><p>发布链建议停在草稿箱：事实检查 → 引用与版权 → 品牌与合规 → 链接检查 → 手机预览 → 人工确认账号 → 发布。自动点赞、批量私信、刷评论、绕过平台风控和未经确认的群发，不属于本书推荐的效率场景。</p><p><img src="'+E+'" alt="" loading="lazy"></p><p><img src="'+f+'" alt="" loading="lazy"></p><p><img src="'+B+`" alt="" loading="lazy"></p><h2 id="场景七-发布后不复盘-下一篇仍从零开始" tabindex="-1">场景七：发布后不复盘，下一篇仍从零开始 <a class="header-anchor" href="#场景七-发布后不复盘-下一篇仍从零开始" aria-label="Permalink to &quot;场景七：发布后不复盘，下一篇仍从零开始&quot;">​</a></h2><p>复盘主要是把AI写的和人工修改后的终稿进行对比，让skill自动进化，下一次，它将写出geng</p><p>可以使用 <a href="https://skillhub.cn/skills/skill-article-evolution" target="_blank" rel="noreferrer">公众号写作自我迭代</a> 或小红书运营副驾，把人工修改和数据写回风格库：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>读取本期内容数据、发布版本和人工修改记录，生成复盘。</span></span>
<span class="line"><span>先陈述数据事实，再列出最多 3 个可验证假设，不把相关性写成因果。</span></span>
<span class="line"><span>把表现按选题、标题、封面、开头、结构、发布时间和渠道拆开。</span></span>
<span class="line"><span>为下轮设计 2 个单变量实验，并说明成功指标和停止条件。</span></span>
<span class="line"><span>将长期有效的修改规则写入 style-guide.md；一次性热点不要写入永久规则。</span></span></code></pre></div><p>把AI最开始产出的文案和终稿都丢进去，最终产出复盘报告和style-guide.md，下次AI写的东西就能离你的期望更进一步啦～</p><p><img src="`+A+'" alt="" loading="lazy"></p><p><img src="'+x+'" alt="" loading="lazy"></p><h2 id="一套够用的自媒体-skill-栈" tabindex="-1">一套够用的自媒体 Skill 栈 <a class="header-anchor" href="#一套够用的自媒体-skill-栈" aria-label="Permalink to &quot;一套够用的自媒体 Skill 栈&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>先装什么</th><th>何时再增加</th></tr></thead><tbody><tr><td>入门</td><td>热门内容查询、标题评分、图片生成</td><td>已能稳定完成一篇内容</td></tr><tr><td>稳定</td><td>评论洞察、封面、排版草稿、违禁词检测</td><td>已明确账号定位和审核人</td></tr><tr><td>多平台</td><td>小红书卡片、短视频脚本、平台适配</td><td>已有统一事实包</td></tr><tr><td>进阶</td><td>数据回流、风格迭代、定时选题雷达</td><td>人工流程已连续跑通 4 周</td></tr></tbody></table>',71))])}const I=e(y,[["render",v]]);export{S as __pageData,I as default};
